module pulse_gen(
    input clk,
    input trigger,
    output reg pulse
);

    reg obf_trigger_prev = 0;

    always @(posedge clk) begin
        if (trigger && !obf_trigger_prev) begin
            pulse <= 1;
        end else begin
            pulse <= 0;
        end
        obf_trigger_prev <= trigger;
    end

endmodule
